Implement UI primitive components and type definitions.

Working directory: /Users/so/MyWorkSpace/personal/care-inomi/.worktrees/feature/initial-setup

1. Create src/types/ui.ts:

```typescript
import type { HTMLAttributes } from "astro/types";

// Navigation types
export interface NavItem {
  label: string;
  href: string;
  children?: NavItem[];
}

// Service card type
export interface ServiceCard {
  id: string;
  icon: string;
  title: string;
  description: string;
  href: string;
}

// FAQ item type
export interface FAQItem {
  question: string;
  answer: string;
}

// Timeline event type
export interface TimelineEvent {
  year: string;
  title: string;
  description: string;
}

// Button variants
export type ButtonVariant = "primary" | "secondary" | "outline";
export type ButtonSize = "sm" | "md" | "lg";

export interface ButtonProps extends Omit<HTMLAttributes<"button">, "class"> {
  variant?: ButtonVariant;
  size?: ButtonSize;
  href?: string;
  class?: string;
}
```

2. Create src/types/content.ts:

```typescript
// SEO metadata
export interface SEOProps {
  title: string;
  description: string;
  ogImage?: string;
  ogType?: "website" | "article";
  noIndex?: boolean;
  canonicalUrl?: string;
}

// Structured data types
export interface OrganizationSchema {
  name: string;
  url: string;
  logo?: string;
  address?: {
    addressCountry: string;
    addressRegion?: string;
    addressLocality?: string;
  };
}

export interface FAQPageSchema {
  questions: {
    question: string;
    answer: string;
  }[];
}
```

3. Create src/components/ui/Button.astro:

```astro
---
import type { ButtonVariant, ButtonSize } from "../../types/ui";
import { cn } from "../../lib/utils";

interface Props {
  variant?: ButtonVariant;
  size?: ButtonSize;
  href?: string;
  class?: string;
  [key: string]: unknown;
}

const { variant = "primary", size = "md", href, class: className, ...rest } = Astro.props;

const baseStyles = "inline-flex items-center justify-center font-medium rounded-lg transition-all duration-normal focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-sakura-500 focus-visible:ring-offset-2 disabled:opacity-50 disabled:cursor-not-allowed";

const variants: Record<ButtonVariant, string> = {
  primary: "bg-sakura-500 text-white hover:bg-sakura-600 active:bg-sakura-700",
  secondary: "bg-neutral-100 text-neutral-800 hover:bg-neutral-200 active:bg-neutral-300",
  outline: "border-2 border-sakura-500 text-sakura-600 hover:bg-sakura-50 active:bg-sakura-100",
};

const sizes: Record<ButtonSize, string> = {
  sm: "px-3 py-1.5 text-sm min-h-[36px]",
  md: "px-5 py-2.5 text-base min-h-[44px]",
  lg: "px-7 py-3 text-lg min-h-[52px]",
};

const classes = cn(baseStyles, variants[variant], sizes[size], className);

const Tag = href ? "a" : "button";
---

{href ? (
  <a href={href} class={classes} {...rest}>
    <slot />
  </a>
) : (
  <button class={classes} {...rest}>
    <slot />
  </button>
)}
```

4. Create src/components/ui/Container.astro:

```astro
---
import { cn } from "../../lib/utils";

interface Props {
  class?: string;
  as?: "div" | "section" | "article" | "main";
}

const { class: className, as: Tag = "div" } = Astro.props;
---

<Tag class={cn("mx-auto w-full max-w-7xl px-4 sm:px-6 lg:px-8", className)}>
  <slot />
</Tag>
```

